// LocalStorage-backed reactive hooks for watchlists and compare list.
import { useEffect, useState, useCallback, useMemo } from "react";

const CMP_KEY = "castia.compare";
const WATCHLISTS_KEY = "castia.watchlists";
const MAX_COMPARE = 5;

function storageEventName(key) {
  return `castia:${key.replace("castia.", "")}`;
}

function readSet(key) {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return new Set();
    const arr = JSON.parse(raw);
    return new Set(Array.isArray(arr) ? arr : []);
  } catch {
    return new Set();
  }
}

function writeSet(key, set) {
  try {
    localStorage.setItem(key, JSON.stringify(Array.from(set)));
    window.dispatchEvent(new CustomEvent(storageEventName(key)));
  } catch {
    /* quota exceeded — ignore */
  }
}

function useStorageSet(key) {
  const [set, setSet] = useState(() => readSet(key));

  useEffect(() => {
    const handler = () => setSet(readSet(key));
    window.addEventListener(storageEventName(key), handler);
    window.addEventListener("storage", handler);
    return () => {
      window.removeEventListener(storageEventName(key), handler);
      window.removeEventListener("storage", handler);
    };
  }, [key]);

  const toggle = useCallback(
    (value) => {
      const next = new Set(set);
      if (next.has(value)) next.delete(value);
      else next.add(value);
      writeSet(key, next);
      setSet(next);
      return next.has(value);
    },
    [set, key]
  );

  const has = useCallback((value) => set.has(value), [set]);

  const clear = useCallback(() => {
    writeSet(key, new Set());
    setSet(new Set());
  }, [key]);

  return { items: Array.from(set), has, toggle, clear, count: set.size };
}

export function useCompare() {
  const base = useStorageSet(CMP_KEY);
  const add = useCallback((key) => {
    if (base.has(key)) {
      base.toggle(key);
      return { added: false };
    }
    if (base.count >= MAX_COMPARE) {
      return { added: false, full: true };
    }
    base.toggle(key);
    return { added: true };
  }, [base]);
  return { ...base, add, max: MAX_COMPARE };
}

const WATCHLISTS_DEFAULT = { id: "favorites", name: "Favorites", items: [] };

function readWatchlists() {
  try {
    const raw = localStorage.getItem(WATCHLISTS_KEY);
    if (!raw) {
      // Check for legacy favorites and migrate them
      const legacyFavs = localStorage.getItem("castia.favorites");
      if (legacyFavs) {
        try {
          const favItems = JSON.parse(legacyFavs);
          if (Array.isArray(favItems) && favItems.length > 0) {
            // Clean up legacy favorites after migration
            localStorage.removeItem("castia.favorites");
            return {
              lists: [
                { id: "favorites", name: "Favorites", items: favItems }
              ],
              currentId: "favorites"
            };
          }
        } catch { /* ignore */ }
      }
      return { lists: [WATCHLISTS_DEFAULT], currentId: "favorites" };
    }
    
    const data = JSON.parse(raw);
    
    // Migration: handle old data that might not have id fields
    if (data.lists) {
      const migratedLists = data.lists.map(list => {
        if (!list.id) {
          return { 
            ...list, 
            id: list.name.toLowerCase().replace(/\s+/g, "-") || `list-${Date.now()}`
          };
        }
        // Remap old "default" id to "favorites"
        if (list.id === "default") {
          return { ...list, id: "favorites", name: "Favorites" };
        }
        return list;
      });
      
      // Remap currentId from old "default" to "favorites"
      const currentId = data.currentId === "default" ? "favorites" : data.currentId;
      
      // Ensure we have a valid currentId
      const validCurrentId = migratedLists.some(list => list.id === currentId) 
        ? currentId 
        : migratedLists[0]?.id || "favorites";
      
      return { lists: migratedLists, currentId: validCurrentId };
    }
    
    // If data doesn't have lists property, return default
    return { lists: [WATCHLISTS_DEFAULT], currentId: "favorites" };
  } catch {
    return { lists: [WATCHLISTS_DEFAULT], currentId: "favorites" };
  }
}

function writeWatchlists(data) {
  try {
    localStorage.setItem(WATCHLISTS_KEY, JSON.stringify(data));
    window.dispatchEvent(new CustomEvent(storageEventName(WATCHLISTS_KEY)));
  } catch {}
}

export function useWatchlists() {
  const [state, setState] = useState(() => readWatchlists());

  useEffect(() => {
    const handler = () => setState(readWatchlists());
    window.addEventListener(storageEventName(WATCHLISTS_KEY), handler);
    window.addEventListener("storage", handler);
    return () => {
      window.removeEventListener(storageEventName(WATCHLISTS_KEY), handler);
      window.removeEventListener("storage", handler);
    };
  }, []);

  const currentList = state.lists.find(l => l.id === state.currentId) || state.lists[0];
  const currentItems = useMemo(() => new Set(currentList?.items || []), [currentList?.items]);

  const current = {
    id: state.currentId,
    name: currentList?.name || "Default",
    items: currentList?.items || [],
    has: useCallback((key) => currentItems.has(key), [currentItems]),
    toggle: useCallback((key) => {
      const next = new Set(currentItems);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      const lists = state.lists.map(l => l.id === state.currentId ? { ...l, items: Array.from(next) } : l);
      writeWatchlists({ lists, currentId: state.currentId });
      setState({ lists, currentId: state.currentId });
      return !next.has(key);
    }, [currentItems, state, setState]),
    clear: useCallback(() => {
      const lists = state.lists.map(l => l.id === state.currentId ? { ...l, items: [] } : l);
      writeWatchlists({ lists, currentId: state.currentId });
      setState({ lists, currentId: state.currentId });
    }, [state, setState]),
    count: currentItems.size,
  };

  const switchList = useCallback((id) => {
    const lists = state.lists.map(l => l.id === id ? l : { ...l });
    writeWatchlists({ lists, currentId: id });
    setState({ lists: state.lists, currentId: id });
  }, [state]);

  const createList = useCallback((name) => {
    const id = name.toLowerCase().replace(/\s+/g, "-").slice(0, 20) || `list-${Date.now()}`;
    const newList = { id, name, items: [] };
    writeWatchlists({ lists: [...state.lists, newList], currentId: id });
    setState({ lists: [...state.lists, newList], currentId: id });
    return id;
  }, [state]);

  const deleteList = useCallback((id) => {
    if (state.lists.length <= 1) return;
    const lists = state.lists.filter(l => l.id !== id);
    const currentId = lists.find(l => l.id === state.currentId) ? state.currentId : lists[0].id;
    writeWatchlists({ lists, currentId });
    setState({ lists, currentId });
  }, [state]);

  const renameList = useCallback((id, newName) => {
    const lists = state.lists.map(l => l.id === id ? { ...l, name: newName } : l);
    writeWatchlists({ lists, currentId: state.currentId });
    setState({ lists, currentId: state.currentId });
  }, [state]);

  return {
    ...current,
    lists: state.lists,
    switchList,
    createList,
    deleteList,
    renameList,
  };
}
